import React, { useState, useEffect } from 'react';
import axios from 'axios';

// Hierarchical Curriculum Structure: Unit -> Topic -> Subtopic
const CURRICULUM = {
  "Unit 1: Building Materials & Construction Practices": {
    "Building Materials": [
      "Brick", "Stones", "Aggregates & M-Sand", "Cement", "Admixtures",
      "Concrete (Self-compacting concrete)", "Mix Design", "Timber",
      "Recycled and modern materials - glass, plastic FRP, ceramic, steel"
    ],
    "Construction Practices": [
      "Masonry", "Construction Equipments", "Building bye-laws",
      "Provisions for fire safety, lighting and ventilation", "Acoustics"
    ]
  },
  "Unit 2: Engineering Survey": {
    "Surveying Fundamentals": [
      "Basics of Surveying", "Chain Surveying", "Compass Surveying", "Plane Table Surveying"
    ],
    "Advanced Surveying": [
      "Levelling", "Computation of area and volume: L.S. and C.S.", "Contouring",
      "Theodolite surveying", "Traversing", "Tacheometry", "Triangulation", "Modern Surveying Techniques"
    ]
  },
  "Unit 3: Engineering Mechanics & Strength of Materials": {
    "Engineering Mechanics": [
      "Forces: Types & Laws", "CoG & MI", "Friction"
    ],
    "Strength of Materials": [
      "Stresses and Strains", "Beams: SFD & BMD", "Theory of simple bending",
      "Deflection of beams", "Torsion", "Combined stresses",
      "Stress Transformations & Failure Theories", "Analysis of plane trusses"
    ]
  },
  "Unit 4: Structural Analysis": {
    "Analysis Methods": [
      "Introduction to Analysis of Structures", "Force/Flexibility Methods of Analysis",
      "Displacement/Stiffness Methods of Analysis", "Matrix method"
    ],
    "Structural Elements": [
      "Arches", "Suspension cables", "Theory of columns",
      "Moving Loads and Influence Lines", "Plastic theory", "Seismic analysis of high rise building"
    ]
  },
  "Unit 5: Geotechnical Engineering": {
    "Soil Mechanics": [
      "Formation & Types of soils", "Physical properties and testing of soils",
      "Classification of Soils for Engineering Practice", "Permeability of Soil",
      "Stress distribution in Soil", "Theory of Consolidation", "Shear strength of Soil",
      "Stability analysis of slope", "Compaction of Soil"
    ],
    "Foundation Engineering": [
      "Shallow foundations", "Pile foundation",
      "Soil exploration & Sampling techniques", "Stabilization of soil",
      "Ground Improvement techniques"
    ]
  },
  "Unit 6: Environmental Engineering": {
    "Water Supply": [
      "Sources & Demand of water", "Hydraulics for conveyance and transmission",
      "Characteristics, analysis of water & water borne diseases", "Functional design of water treatment",
      "Desalination plant", "Water distribution system & Pipe network analysis"
    ],
    "Waste Management": [
      "Planning and design of sewerage system & storm water drain",
      "Sewer appurtenances - Pumping & plumbing system in high rise building",
      "Characteristics and composition of sewage", "Sewage treatment and disposal",
      "Industrial waste water treatment", "Solid waste management",
      "Air and Noise pollution control", "E-Waste management"
    ]
  },
  "Unit 7: RCC / Prestressed Concrete & Steel Structures": {
    "RCC Design": [
      "Working stress design concepts", "Limit state design concepts",
      "Design of Slabs (one way, Two way & Flat slabs)",
      "Design of Beam (singly, doubly reinforced & flanged sections)",
      "Design of Columns & Footings", "Staircase & Lintel",
      "Design of liquid storage structures (elevated and underground)",
      "Design of Retaining wall"
    ],
    "Prestressed & Steel": [
      "Pre-stressing - systems and Methods",
      "Design of Pre-Stressed Members for Flexure & Post tensioning slabs",
      "Design of Bolted and Welded connections", "Design of Tension members",
      "Design of Columns and Bases", "Design of Beams",
      "Design of Plate girder and Gantry girders", "Design of Members of Truss"
    ]
  },
  "Unit 8: Hydraulics & Water Resources": {
    "Fluid Mechanics": [
      "Fluid Properties (Basics)", "Hydrostatic Pressure", "Kinematics of flow",
      "Fluid Dynamics (Applications of Bernoulli & Momentum equation)",
      "Flow through Pipes (Losses)", "Flow measurement in Channel", "Open Channel Flow",
      "Types of Pumps and Characteristics"
    ],
    "Water Resources": [
      "Water resources Planning and Management", "Runoff Estimation",
      "Hydrograph", "Flood Routing", "Flood Control",
      "Soil plant water relationship & Water requirements", "Irrigation Methods",
      "Design of Alluvial Canals", "Design of Head works",
      "Water logging and Land reclamation", "Cross Drainage works"
    ]
  },
  "Unit 9: Urban & Transportation Engineering": {
    "Transportation": [
      "Geometric Design of Highways", "Pavement Materials and Testing",
      "Design, Construction & Maintenance of Roads", "Railway Engineering",
      "Airport Engineering", "Harbour and Docks"
    ],
    "Urban Planning": [
      "Urbanization and Slum", "Traffic Engineering"
    ]
  },
  "Unit 10: Project Management & Estimating": {
    "Management": [
      "Construction Management", "Project Management"
    ],
    "Estimating": [
      "Estimation", "Tender", "Building Valuation"
    ]
  }
};

// Define constants outside component
const UNITS = Object.keys(CURRICULUM);
const DEFAULT_UNIT = UNITS[0];
const DEFAULT_TOPIC = Object.keys(CURRICULUM[DEFAULT_UNIT])[0];
const DEFAULT_SUBTOPIC = CURRICULUM[DEFAULT_UNIT][DEFAULT_TOPIC][0];

function AIGenerator() {
  const [curriculum, setCurriculum] = useState({});
  const [selectedUnit, setSelectedUnit] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('');
  const [selectedSubtopic, setSelectedSubtopic] = useState(null); // Now stores {name, id}
  const [loadingCurriculum, setLoadingCurriculum] = useState(true);
  const [notebookUrl, setNotebookUrl] = useState('');
  const [pastedContent, setPastedContent] = useState('');
  const [batch, setBatch] = useState([]);
  const [loading, setLoading] = useState(false);
  const [questionCount, setQuestionCount] = useState(0);
  const [message, setMessage] = useState('');

  // Fetch curriculum from backend
  useEffect(() => {
    const fetchCurriculum = async () => {
      try {
        console.log('Fetching curriculum...');
        const response = await axios.get('/api/questions/curriculum');
        console.log('Curriculum response:', response.data);
        setCurriculum(response.data);
        setLoadingCurriculum(false);

        // Set default selections
        const units = Object.keys(response.data);
        console.log('Available units:', units);
        if (units.length > 0) {
          const defaultUnit = units[0];
          const topics = Object.keys(response.data[defaultUnit]);
          const defaultTopic = topics[0];
          const defaultSubtopic = response.data[defaultUnit][defaultTopic][0]; // {name, id}

          console.log('Setting defaults:', { defaultUnit, defaultTopic, defaultSubtopic });
          setSelectedUnit(defaultUnit);
          setSelectedTopic(defaultTopic);
          setSelectedSubtopic(defaultSubtopic);
        } else {
          console.warn('No units found in curriculum');
        }
      } catch (error) {
        console.error('Error fetching curriculum:', error);
        setLoadingCurriculum(false);
      }
    };

    fetchCurriculum();
  }, []);

  // Get units from curriculum
  const units = Object.keys(curriculum);

  // Get topics for selected unit
  const topics = selectedUnit ? Object.keys(curriculum[selectedUnit] || {}) : [];

  // Get subtopics for selected topic (array of {name, id} objects)
  const subtopics = selectedUnit && selectedTopic ? (curriculum[selectedUnit][selectedTopic] || []) : [];

  useEffect(() => {
    // Reset topic and subtopic when unit changes
    if (selectedUnit && curriculum[selectedUnit]) {
      const newTopics = Object.keys(curriculum[selectedUnit]);
      if (newTopics.length > 0) {
        setSelectedTopic(newTopics[0]);
        const newSubtopics = curriculum[selectedUnit][newTopics[0]];
        if (newSubtopics && newSubtopics.length > 0) {
          setSelectedSubtopic(newSubtopics[0]);
        }
      }
    }
  }, [selectedUnit, curriculum]);

  useEffect(() => {
    // Reset subtopic when topic changes
    if (selectedUnit && selectedTopic && curriculum[selectedUnit]) {
      const newSubtopics = curriculum[selectedUnit][selectedTopic];
      if (newSubtopics && newSubtopics.length > 0) {
        setSelectedSubtopic(newSubtopics[0]);
      }
    }
  }, [selectedTopic, selectedUnit, curriculum]);

  useEffect(() => {
    fetchQuestionCount();
  }, [selectedSubtopic]);

  const fetchQuestionCount = async () => {
    try {
      const subtopicName = selectedSubtopic?.name || '';
      const response = await axios.get(`/api/questions/stats/count?subtopic=${encodeURIComponent(subtopicName)}`);
      setQuestionCount(response.data.count);
    } catch (error) {
      console.error('Error fetching count:', error);
    }
  };

  const handleQuickExtract = async () => {
    if (!pastedContent) {
      alert('Please paste content first!');
      return;
    }

    // Calculate how many more questions needed
    const remaining = Math.max(0, 25 - questionCount);
    if (remaining === 0) {
      alert('This subtopic already has 25 questions!');
      return;
    }

    setLoading(true);
    try {
      console.log('Sending content length:', pastedContent.length);
      const response = await axios.post('/api/ai/extract', {
        textContent: pastedContent,
        unit: selectedUnit,
        topic: selectedTopic,
        subtopic: selectedSubtopic?.name || '',
        subtopicId: selectedSubtopic?.id || null,
        maxQuestions: remaining
      });

      console.log('Extracted questions:', response.data.questions.length);
      const questions = response.data.questions.map((q, idx) => ({
        ...q,
        id: Date.now() + idx,
        status: 'PENDING'
      }));
      setBatch(questions);

      if (questions.length === 0) {
        setMessage('No questions found in the pasted content. Make sure your questions are numbered (1., 2., etc.) and have options (a, b, c, d).');
      } else {
        setMessage(`Extracted ${questions.length} question${questions.length > 1 ? 's' : ''}. Review and save them.`);
      }
    } catch (error) {
      alert('Extraction failed: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const addManualQuestion = () => {
    setBatch([{
      id: Date.now(),
      question: 'New Concept Question',
      options: { a: '', b: '', c: '', d: '' },
      correct_answer: 'a',
      explanation: '',
      type: 'Theory-based MCQ',
      unit: selectedUnit,
      topic: selectedTopic,
      subtopic: selectedSubtopic?.name || '',
      subtopicId: selectedSubtopic?.id || null,
      status: 'APPROVED'
    }, ...batch]);
  };

  const updateQuestion = (id, field, value) => {
    setBatch(batch.map(q => q.id === id ? { ...q, [field]: value } : q));
  };

  const updateOption = (id, key, value) => {
    setBatch(batch.map(q =>
      q.id === id ? { ...q, options: { ...q.options, [key]: value } } : q
    ));
  };

  const handleImageUpload = async (e, id, type, optionKey = null) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('image', file);

    try {
      const response = await axios.post('/api/questions/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      const imageUrl = response.data.imageUrl;

      setBatch(batch.map(q => {
        if (q.id !== id) return q;

        if (type === 'question') {
          return { ...q, questionImage: imageUrl };
        } else if (type === 'explanation') {
          return { ...q, explanationImage: imageUrl };
        } else if (type === 'option' && optionKey) {
          const newOptionImages = { ...(q.optionImages || { a: null, b: null, c: null, d: null }) };
          newOptionImages[optionKey] = imageUrl;
          return { ...q, optionImages: newOptionImages };
        }
        return q;
      }));
    } catch (error) {
      alert('Image upload failed: ' + error.message);
    }
  };

  const removeImage = (id, type, optionKey = null) => {
    setBatch(batch.map(q => {
      if (q.id !== id) return q;

      if (type === 'question') {
        return { ...q, questionImage: null };
      } else if (type === 'explanation') {
        return { ...q, explanationImage: null };
      } else if (type === 'option' && optionKey) {
        const newOptionImages = { ...(q.optionImages || { a: null, b: null, c: null, d: null }) };
        newOptionImages[optionKey] = null;
        return { ...q, optionImages: newOptionImages };
      }
      return q;
    }));
  };

  const getImagePreview = (imageUrl) => {
    if (!imageUrl) return null;
    return imageUrl.startsWith('http') ? imageUrl : `http://localhost:5000${imageUrl}`;
  };

  const saveSingleQuestion = async (id) => {
    const q = batch.find(item => item.id === id);
    if (!q) return;

    setLoading(true);
    try {
      // Convert to new schema format
      const answerMap = { 'a': 0, 'b': 1, 'c': 2, 'd': 3 };
      const questionData = {
        unit: q.unit || selectedUnit,
        topic: q.topic || selectedTopic,
        subtopic: q.subtopic || (selectedSubtopic?.name || ''),
        subtopicId: q.subtopicId || (selectedSubtopic?.id || null),
        type: q.type || 'Theory-based MCQ',
        question: q.question,
        questionImage: q.questionImage || null,
        options: q.options,
        optionImages: q.optionImages || { a: null, b: null, c: null, d: null },
        correctAnswer: answerMap[q.correct_answer] || 0,
        explanation: q.explanation || '',
        explanationImage: q.explanationImage || null,
        status: 'accepted',
        is_published: false
      };

      await axios.post('/api/questions', questionData);

      // Remove from batch after successful save
      setBatch(batch.filter(item => item.id !== id));
      setMessage('Question saved successfully!');
      fetchQuestionCount();
    } catch (error) {
      setMessage('Error saving question: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const setStatus = (id, status) => {
    if (status === 'APPROVED') {
      saveSingleQuestion(id);
    } else {
      setBatch(batch.map(q => q.id === id ? { ...q, status } : q));
    }
  };

  const deleteQuestion = (id) => {
    setBatch(batch.filter(q => q.id !== id));
  };

  const clearBatch = () => {
    setBatch([]);
  };

  const saveAll = async () => {
    const toSave = batch.filter(q => q.status !== 'REJECTED');
    if (toSave.length === 0) {
      alert('No questions to save!');
      return;
    }

    setLoading(true);
    try {
      const answerMap = { 'a': 0, 'b': 1, 'c': 2, 'd': 3 };

      for (const q of toSave) {
        const questionData = {
          unit: q.unit || selectedUnit,
          topic: q.topic || selectedTopic,
          subtopic: q.subtopic || selectedSubtopic,
          type: q.type || 'Theory-based MCQ',
          question: q.question,
          questionImage: q.questionImage || null,
          options: q.options,
          optionImages: q.optionImages || { a: null, b: null, c: null, d: null },
          correctAnswer: answerMap[q.correct_answer] || 0,
          explanation: q.explanation || '',
          explanationImage: q.explanationImage || null,
          status: 'accepted',
          is_published: false
        };
        await axios.post('/api/questions', questionData);
      }
      setMessage(`Successfully saved ${toSave.length} questions!`);
      setBatch([]);
      fetchQuestionCount();
    } catch (error) {
      setMessage('Error saving: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const progressPct = Math.min(100, (questionCount / 25) * 100);

  const seedCurriculum = async () => {
    try {
      setLoading(true);
      const response = await axios.post('/api/questions/curriculum/seed');
      alert(response.data.message);
      // Refresh curriculum
      const curriculumResponse = await axios.get('/api/questions/curriculum');
      setCurriculum(curriculumResponse.data);
    } catch (error) {
      alert('Error seeding curriculum: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  if (loadingCurriculum) {
    return (
      <div className="tab-content">
        <h2>Question Extractor</h2>
        <div className="info-box">Loading curriculum...</div>
      </div>
    );
  }

  if (units.length === 0) {
    return (
      <div className="tab-content">
        <h2>Question Extractor</h2>
        <div className="info-box">
          No curriculum found. Please seed the curriculum first.
        </div>
        <button className="btn-primary" onClick={seedCurriculum} disabled={loading}>
          {loading ? 'Seeding...' : 'Seed Curriculum'}
        </button>
      </div>
    );
  }

  return (
    <div className="tab-content">
      <h2>Question Extractor</h2>

      <div className="info-box">
        Paste content to extract questions automatically. Review and save individual questions or approve all at once.
      </div>

      <div className="form-row">
        <div className="form-group">
          <label>Select Unit</label>
          <select value={selectedUnit} onChange={(e) => setSelectedUnit(e.target.value)}>
            {units.map(u => <option key={u} value={u}>{u}</option>)}
          </select>
        </div>
        <div className="form-group">
          <label>Select Topic</label>
          <select value={selectedTopic} onChange={(e) => setSelectedTopic(e.target.value)}>
            {topics.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>
        <div className="form-group">
          <label>Select Subtopic</label>
          <select
            value={selectedSubtopic?.id || ''}
            onChange={(e) => {
              const selected = subtopics.find(st => st.id === e.target.value);
              setSelectedSubtopic(selected || null);
            }}
          >
            {subtopics.map(st => <option key={st.id} value={st.id}>{st.name}</option>)}
          </select>
        </div>
      </div>

      <div className="progress-container">
        <div className="progress-header">
          <span className="progress-title">Live Subtopic Pulse: {selectedSubtopic?.name || ''}</span>
          <span className={`progress-count ${questionCount >= 25 ? 'complete' : ''}`}>
            {questionCount} / 25 Questions Verified
          </span>
        </div>
        <div className="progress-bar">
          <div
            className={`progress-fill ${questionCount >= 25 ? 'complete' : ''}`}
            style={{ width: `${progressPct}%` }}
          />
        </div>
        {questionCount >= 25 ? (
          <div style={{ color: '#008000', marginTop: '8px', fontWeight: 700 }}>Subtopic Complete!</div>
        ) : (
          <div style={{ color: '#000000', marginTop: '8px' }}>Add {25 - questionCount} more to unlock for students.</div>
        )}
      </div>

      <div className="form-group">
        <label>Paste Notebook LLM Source URL</label>
        <input 
          type="text" 
          value={notebookUrl} 
          onChange={(e) => setNotebookUrl(e.target.value)}
          placeholder="https://notebooklm.google.com/..."
        />
      </div>

      <div className="form-group">
        <label>Paste Questions Content</label>
        <textarea
          value={pastedContent}
          onChange={(e) => setPastedContent(e.target.value)}
          rows={10}
          placeholder={`Paste your questions here in this format:

1. What is the capital of France?
a) London
b) Paris
c) Berlin
d) Madrid
Answer: b
Explanation: Paris is the capital of France.

2. What is 2+2?
a) 3
b) 4
c) 5
d) 6
Answer: b`}
        />
        <small style={{ color: '#000000', display: 'block', marginTop: '8px' }}>
          Format: Numbered questions with options (a, b, c, d) and optional Answer/Explanation
        </small>
      </div>

      <div className="action-row">
        <button
          className="btn-primary"
          onClick={handleQuickExtract}
          disabled={loading}
        >
          {loading ? 'Extracting...' : 'Extract Questions'}
        </button>
      </div>

      {message && (
        <div className={message.includes('Error') ? 'error-message' : 'success-message'}>
          {message}
        </div>
      )}

      {batch.length > 0 && (
        <>
          <div className="action-row" style={{ marginTop: '24px' }}>
            <button className="btn-secondary" onClick={addManualQuestion}>
              Add Manual Question
            </button>
            <button className="btn-primary" onClick={saveAll} disabled={loading}>
              {loading ? 'Saving...' : 'Approve & Save Everything'}
            </button>
            <button className="btn-danger" onClick={clearBatch}>
              Clear Review List
            </button>
          </div>

          <h3 style={{ marginTop: '24px', marginBottom: '16px' }}>Review Mode & Question Management</h3>

          {batch.map((q, idx) => (
            <div key={q.id} className={`question-card ${q.status.toLowerCase()}`}>
              <div className="question-header">
                <h3>Question {idx + 1}</h3>
                <span className={`status-badge ${q.status.toLowerCase()}`}>{q.status}</span>
              </div>
              
              <div className="question-topic">[{q.subcategory}]</div>
              
              <div className="edit-form">
                {/* Question Section */}
                <div className="section">
                  <h4>Question</h4>
                  <div className="form-group">
                    <label>Question Text</label>
                    <textarea
                      value={q.question}
                      onChange={(e) => updateQuestion(q.id, 'question', e.target.value)}
                      rows={3}
                    />
                  </div>
                  <div className="form-group">
                    <label>Question Image (Optional)</label>
                    <input
                      type="file"
                      accept="image/*"
                      onChange={(e) => handleImageUpload(e, q.id, 'question')}
                    />
                    {q.questionImage && (
                      <div className="image-preview-container">
                        <img
                          src={getImagePreview(q.questionImage)}
                          alt="Question"
                          className="image-preview"
                        />
                        <button type="button" className="btn-remove-image" onClick={() => removeImage(q.id, 'question')}>
                          Remove
                        </button>
                      </div>
                    )}
                  </div>
                </div>

                {/* Options Section */}
                <div className="section">
                  <h4>Options</h4>
                  {['a', 'b', 'c', 'd'].map((opt) => (
                    <div key={opt} className="option-row">
                      <div className="option-input-group">
                        <div className="form-group option-text">
                          <label>Option {opt.toUpperCase()}</label>
                          <input
                            value={q.options[opt]}
                            onChange={(e) => updateOption(q.id, opt, e.target.value)}
                          />
                        </div>
                        <div className="form-group option-image">
                          <label>Image</label>
                          <input
                            type="file"
                            accept="image/*"
                            onChange={(e) => handleImageUpload(e, q.id, 'option', opt)}
                          />
                          {q.optionImages?.[opt] && (
                            <div className="image-preview-small">
                              <img
                                src={getImagePreview(q.optionImages[opt])}
                                alt={`Option ${opt.toUpperCase()}`}
                              />
                              <button type="button" className="btn-remove-small" onClick={() => removeImage(q.id, 'option', opt)}>
                                x
                              </button>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="form-group">
                  <label>Correct Answer</label>
                  <select
                    value={q.correct_answer}
                    onChange={(e) => updateQuestion(q.id, 'correct_answer', e.target.value)}
                  >
                    <option value="a">A</option>
                    <option value="b">B</option>
                    <option value="c">C</option>
                    <option value="d">D</option>
                  </select>
                </div>

                {/* Explanation Section */}
                <div className="section">
                  <h4>Explanation</h4>
                  <div className="form-group">
                    <label>Explanation Text</label>
                    <textarea
                      value={q.explanation}
                      onChange={(e) => updateQuestion(q.id, 'explanation', e.target.value)}
                      rows={4}
                      placeholder="Enter detailed explanation here..."
                    />
                  </div>
                  <div className="form-group">
                    <label>Explanation Image (Optional)</label>
                    <input
                      type="file"
                      accept="image/*"
                      onChange={(e) => handleImageUpload(e, q.id, 'explanation')}
                    />
                    {q.explanationImage && (
                      <div className="image-preview-container">
                        <img
                          src={getImagePreview(q.explanationImage)}
                          alt="Explanation"
                          className="image-preview"
                        />
                        <button type="button" className="btn-remove-image" onClick={() => removeImage(q.id, 'explanation')}>
                          Remove
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              <div className="card-actions">
                <button className="btn-primary" onClick={() => setStatus(q.id, 'APPROVED')}>
                  Save & Accept
                </button>
                <button className="btn-danger" onClick={() => setStatus(q.id, 'REJECTED')}>
                  Reject
                </button>
                <button className="btn-danger" onClick={() => deleteQuestion(q.id)}>
                  Delete
                </button>
              </div>
            </div>
          ))}
        </>
      )}
    </div>
  );
}

export default AIGenerator;
